import React, { useState, useEffect } from 'react';
import { authAPI, addressAPI } from '/home/sidhu/Desktop/ECommerceAPI/frontend/src/api.js';

const ProfilePage = ({
  user,
  cart,
  orders,
  profileData,
  setProfileData,
  setCurrentPage,
  handleLogout,
  setError,
  loadOrders,
  loading,
  setLoading
}) => {
  const [editMode, setEditMode] = useState(false);
  const [activeTab, setActiveTab] = useState('profile');
  const [loadingProfile, setLoadingProfile] = useState(false);

  useEffect(() => {
    if (!user) return;
    fetchAddresses();
    fetchProfile();
  }, [user]);

  useEffect(() => {
    if (!user) return;
    fetchOrders();
  }, [user]);

  const fetchProfile = async () => {
    try {
      setLoadingProfile(true);
      const res = await authAPI.getProfile();
      const data = res.data;
      setProfileData({
        fullName: data.fullName || user?.name || '',
        email: data.email || user?.email || '',
        mobile: data.mobile || user?.mobile || '',
        gender: data.gender || user?.gender || '',
        addresses: data.addresses || []
      });
    } catch (err) {
      if (user) {
        setProfileData({
          fullName: user.name || '',
          email: user.email || '',
          mobile: user.mobile || '',
          gender: user.gender || '',
          addresses: []
        });
      }
    } finally {
      setLoadingProfile(false);
    }
  };

  const fetchAddresses = async () => {
    try {
      let currentUserId = null;
      try {
        const profileRes = await authAPI.getProfile();
        currentUserId = profileRes.data?.id || profileRes.data?.userId || profileRes.data?.Id;
      } catch {
        currentUserId = user?.id || user?.userId;
      }

      let res;
      if (typeof addressAPI?.getAll === 'function') {
        res = await addressAPI.getAll();
      } else {
        setProfileData(prev => ({ ...prev, addresses: [] }));
        return;
      }

      const rawAddresses = Array.isArray(res.data) ? res.data : (res.data?.addresses || []);
      const userAddresses = currentUserId
        ? rawAddresses.filter(a => {
            const addrUserId = a.userId || a.UserId || a.user_id;
            return addrUserId === currentUserId || addrUserId === String(currentUserId);
          })
        : rawAddresses;

      const normalized = userAddresses.map((a, index) => ({
        id: a.Id || a.id || `addr_${Date.now()}_${index}`,
        label: a.Label || a.label || (a.IsDefault ? 'Home' : 'Address'),
        AddressLine1: a.AddressLine1 || a.addressLine1 || '',
        AddressLine2: a.AddressLine2 || a.addressLine2 || '',
        City: a.City || a.city || '',
        State: a.State || a.state || '',
        PostalCode: a.PostalCode || a.postalCode || '',
        Country: a.Country || a.country || '',
        IsDefault: !!(a.IsDefault || a.isDefault),
        userId: a.userId || a.UserId || currentUserId
      }));

      setProfileData(prev => ({ ...prev, addresses: normalized }));
    } catch (err) {
      setProfileData(prev => ({ ...prev, addresses: [] }));
    }
  };

  const handleSaveProfile = async () => {
    try {
      setLoading(true);
      setError('');
      const payload = {
        fullName: profileData.fullName,
        mobile: profileData.mobile,
        gender: profileData.gender
      };
      if (typeof authAPI.updateProfile === 'function') {
        await authAPI.updateProfile(payload);
      }
      const raw = sessionStorage.getItem('user') || localStorage.getItem('user');
      const userData = JSON.parse(raw || '{}');
      const updatedUser = { ...userData, fullName: profileData.fullName, mobile: profileData.mobile, gender: profileData.gender };
      if (sessionStorage.getItem('user')) sessionStorage.setItem('user', JSON.stringify(updatedUser));
      if (localStorage.getItem('user'))   localStorage.setItem('user', JSON.stringify(updatedUser));
      setEditMode(false);
      alert('✅ Profile updated successfully!');
    } catch (err) {
      setError(err.response?.data?.message || err.message || 'Failed to update profile.');
    } finally {
      setLoading(false);
    }
  };

  const fetchOrders = async () => {
    try { await loadOrders(); } catch {}
  };

  const handleAddAddress = async () => {
    try {
      const line1 = window.prompt('Address Line 1');
      if (!line1) return;
      const raw = sessionStorage.getItem('user') || localStorage.getItem('user');
      const userData = JSON.parse(raw || '{}');
      const userId = userData.id || userData.userId || userData.Id;
      if (!userId) { alert('User ID not found. Please re-login.'); return; }
      const payload = {
        userId,
        addressLine1: line1,
        addressLine2: window.prompt('Address Line 2 (optional)') || '',
        city: window.prompt('City') || '',
        state: window.prompt('State (optional)') || '',
        postalCode: window.prompt('Postal Code (optional)') || '',
        country: window.prompt('Country', 'India') || 'India',
        isDefault: window.confirm('Set as default address?')
      };
      await addressAPI.add(payload);
      await fetchAddresses();
      alert('Address added successfully');
    } catch (err) {
      alert(err?.response?.data?.message || err.message || 'Failed to add address');
    }
  };

  const handleDeleteAddress = async (addr) => {
    if (!window.confirm('Delete this address?')) return;
    try {
      await addressAPI.remove(addr.id);
      await fetchAddresses();
    } catch (err) {
      alert('Failed to delete address');
    }
  };

  const genderIcon = { Male: '♂', Female: '♀', Other: '⚧', PreferNotToSay: '–' };

  const totalSpent = orders
    .filter(o => o.status !== 'Cancelled' && o.Status !== 'Cancelled')
    .reduce((s, o) => s + (o.totalAmount || o.TotalAmount || 0), 0);

  return (
    <div style={{ minHeight: '100vh', background: '#f0fdfc', fontFamily: "'DM Sans', system-ui, sans-serif" }}>
      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=DM+Sans:ital,opsz,wght@0,9..40,300;0,9..40,400;0,9..40,500;0,9..40,600;0,9..40,700;1,9..40,400&family=Playfair+Display:wght@700;800&display=swap');
        * { box-sizing: border-box; margin: 0; padding: 0; }
        .tab-btn { cursor: pointer; border: none; background: none; font-family: inherit; }
        .tab-btn:focus { outline: none; }
        .action-btn { cursor: pointer; border: none; font-family: inherit; transition: all 0.2s; }
        .action-btn:hover { opacity: 0.88; transform: translateY(-1px); }
        .action-btn:active { transform: translateY(0); }
        .input-field { font-family: inherit; transition: all 0.2s; outline: none; }
        .input-field:focus { border-color: #06b6d4 !important; box-shadow: 0 0 0 3px rgba(6,182,212,0.15); }
        .addr-card { transition: all 0.2s; }
        .addr-card:hover { transform: translateY(-2px); box-shadow: 0 8px 24px rgba(6,182,212,0.12); }
        .order-row { transition: all 0.15s; }
        .order-row:hover { background: #f0fdfc; }
        .stat-card { transition: transform 0.2s; }
        .stat-card:hover { transform: translateY(-3px); }
        .nav-link { cursor: pointer; transition: all 0.15s; }
        .nav-link:hover { opacity: 0.8; }
        @keyframes fadeIn { from { opacity:0; transform:translateY(8px); } to { opacity:1; transform:translateY(0); } }
        .fade-in { animation: fadeIn 0.35s ease both; }
      `}</style>

      {/* ── HEADER ── */}
      <header style={{ background: 'linear-gradient(135deg, #0e7490 0%, #06b6d4 60%, #22d3ee 100%)', padding: '0 32px', position: 'sticky', top: 0, zIndex: 50, boxShadow: '0 4px 20px rgba(6,182,212,0.3)' }}>
        <div style={{ maxWidth: 1200, margin: '0 auto', height: 68, display: 'flex', alignItems: 'center', justifyContent: 'space-between' }}>
          <div style={{ display: 'flex', alignItems: 'center', gap: 12, cursor: 'pointer' }} onClick={() => setCurrentPage('products')}>
            <div style={{ width: 38, height: 38, background: 'rgba(255,255,255,0.2)', borderRadius: 10, display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: 20 }}>🛍</div>
            <div>
              <div style={{ fontFamily: "'Playfair Display', serif", fontWeight: 800, fontSize: 22, color: '#fff', lineHeight: 1 }}>ShopAI</div>
              <div style={{ fontSize: 10, color: 'rgba(255,255,255,0.7)', letterSpacing: 2, textTransform: 'uppercase' }}>marketplace</div>
            </div>
          </div>

          <div style={{ display: 'flex', alignItems: 'center', gap: 8 }}>
            {[['products','🛍 Shop'],['orders','📦 Orders']].map(([page, label]) => (
              <button key={page} className="nav-link tab-btn" onClick={() => setCurrentPage(page)}
                style={{ color: 'rgba(255,255,255,0.9)', padding: '8px 16px', borderRadius: 8, fontSize: 14, fontWeight: 500 }}>
                {label}
              </button>
            ))}
            <button className="nav-link tab-btn" onClick={() => setCurrentPage('cart')}
              style={{ position: 'relative', color: '#fff', padding: '8px 12px', borderRadius: 8 }}>
              🛒
              {cart.length > 0 && (
                <span style={{ position: 'absolute', top: 2, right: 2, background: '#f97316', color: '#fff', fontSize: 10, fontWeight: 700, borderRadius: 999, width: 18, height: 18, display: 'flex', alignItems: 'center', justifyContent: 'center' }}>{cart.length}</span>
              )}
            </button>
            <button className="action-btn" onClick={handleLogout}
              style={{ background: 'rgba(255,255,255,0.15)', border: '1.5px solid rgba(255,255,255,0.3)', color: '#fff', padding: '8px 18px', borderRadius: 10, fontSize: 14, fontWeight: 600, backdropFilter: 'blur(4px)' }}>
              Sign out
            </button>
          </div>
        </div>
      </header>

      {/* ── PROFILE HERO ── */}
      <div style={{ background: 'linear-gradient(135deg, #0e7490 0%, #0891b2 50%, #06b6d4 100%)', padding: '48px 32px 80px' }}>
        <div style={{ maxWidth: 1200, margin: '0 auto', display: 'flex', alignItems: 'center', gap: 28 }}>
          {/* Avatar */}
          <div style={{ width: 80, height: 80, borderRadius: '50%', background: 'rgba(255,255,255,0.2)', border: '3px solid rgba(255,255,255,0.5)', display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: 32, flexShrink: 0, backdropFilter: 'blur(8px)' }}>
            {(profileData.fullName || user?.name || 'U')[0].toUpperCase()}
          </div>
          <div style={{ flex: 1 }}>
            <div style={{ fontSize: 13, color: 'rgba(255,255,255,0.65)', fontWeight: 500, letterSpacing: 1, textTransform: 'uppercase', marginBottom: 6 }}>Your Account</div>
            <h1 style={{ fontFamily: "'Playfair Display', serif", fontSize: 'clamp(24px, 4vw, 36px)', fontWeight: 800, color: '#fff', lineHeight: 1.15, marginBottom: 4 }}>
