                <div style={{ fontSize: 22, marginBottom: 4 }}>{stat.icon}</div>
                <div style={{ fontSize: 20, fontWeight: 700, color: '#fff', lineHeight: 1 }}>{stat.value}</div>
                <div style={{ fontSize: 11, color: 'rgba(255,255,255,0.65)', marginTop: 2, textTransform: 'uppercase', letterSpacing: 0.5 }}>{stat.label}</div>
              </div>
            ))}
          </div>
        </div>
      </div>

      {/* ── TABS ── */}
      <div style={{ background: '#fff', borderBottom: '1px solid #e2e8f0', position: 'sticky', top: 68, zIndex: 40, boxShadow: '0 2px 8px rgba(0,0,0,0.04)' }}>
        <div style={{ maxWidth: 1200, margin: '0 auto', padding: '0 32px', display: 'flex', gap: 0, marginTop: -1 }}>
          {[
            { id: 'profile', label: 'Profile', icon: '👤' },
            { id: 'addresses', label: 'Addresses', icon: '📍' },
            { id: 'orders', label: 'Orders', icon: '📦' }
          ].map(tab => (
            <button key={tab.id} className="tab-btn" onClick={() => setActiveTab(tab.id)}
              style={{
                padding: '16px 24px', fontSize: 14, fontWeight: 600,
                color: activeTab === tab.id ? '#0891b2' : '#64748b',
                borderBottom: activeTab === tab.id ? '2.5px solid #06b6d4' : '2.5px solid transparent',
                transition: 'all 0.2s', display: 'flex', alignItems: 'center', gap: 8
              }}>
              <span>{tab.icon}</span> {tab.label}
            </button>
          ))}
        </div>
      </div>

      {/* ── MAIN CONTENT ── */}
      <div style={{ maxWidth: 1200, margin: '0 auto', padding: '40px 32px 80px' }}>

        {/* ── TAB: PROFILE ── */}
        {activeTab === 'profile' && (
          <div className="fade-in" style={{ maxWidth: 720 }}>
            <div style={{ background: '#fff', borderRadius: 20, border: '1px solid #e2e8f0', overflow: 'hidden', boxShadow: '0 4px 20px rgba(0,0,0,0.05)' }}>
              {/* Card header */}
              <div style={{ padding: '24px 32px', borderBottom: '1px solid #f1f5f9', display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                <div>
                  <h2 style={{ fontSize: 18, fontWeight: 700, color: '#0f172a' }}>Personal Information</h2>
                  <p style={{ fontSize: 13, color: '#94a3b8', marginTop: 2 }}>Update your name, phone and gender</p>
                </div>
                <button className="action-btn" onClick={editMode ? handleSaveProfile : () => setEditMode(true)}
                  style={{
                    padding: '10px 22px', borderRadius: 10, fontSize: 14, fontWeight: 600, border: 'none',
                    background: editMode ? 'linear-gradient(135deg, #059669, #10b981)' : 'linear-gradient(135deg, #0891b2, #06b6d4)',
                    color: '#fff', boxShadow: editMode ? '0 4px 14px rgba(5,150,105,0.3)' : '0 4px 14px rgba(6,182,212,0.3)'
                  }}>
                  {editMode ? '✓ Save' : '✏ Edit'}
                </button>
              </div>

              {/* Fields */}
              <div style={{ padding: '32px', display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 24 }}>
                {[
                  { label: 'Full Name', key: 'fullName', type: 'text', editable: true },
                  { label: 'Email Address', key: 'email', type: 'email', editable: false, hint: 'Cannot be changed' },
                  { label: 'Mobile Number', key: 'mobile', type: 'tel', editable: true },
                ].map(field => (
                  <div key={field.key}>
                    <label style={{ display: 'block', fontSize: 11, fontWeight: 700, color: '#94a3b8', letterSpacing: 1, textTransform: 'uppercase', marginBottom: 8 }}>
                      {field.label}
                    </label>
                    <input
                      type={field.type}
                      className="input-field"
                      value={(profileData[field.key] || '').toString()}
                      onChange={e => setProfileData({ ...profileData, [field.key]: e.target.value })}
                      disabled={!editMode || !field.editable}
                      style={{
                        width: '100%', padding: '12px 16px', borderRadius: 10, fontSize: 15,
                        border: '1.5px solid', borderColor: editMode && field.editable ? '#a5f3fc' : '#f1f5f9',
                        background: editMode && field.editable ? '#fff' : '#f8fafc',
                        color: editMode && field.editable ? '#0f172a' : '#64748b',
                        cursor: !field.editable || !editMode ? 'not-allowed' : 'text'
                      }} />
                    {field.hint && <p style={{ fontSize: 11, color: '#94a3b8', marginTop: 4 }}>✓ {field.hint}</p>}
                  </div>
                ))}

                <div>
                  <label style={{ display: 'block', fontSize: 11, fontWeight: 700, color: '#94a3b8', letterSpacing: 1, textTransform: 'uppercase', marginBottom: 8 }}>Gender</label>
                  <select
                    className="input-field"
                    value={profileData.gender || ''}
                    onChange={e => setProfileData({ ...profileData, gender: e.target.value })}
                    disabled={!editMode}
                    style={{
                      width: '100%', padding: '12px 16px', borderRadius: 10, fontSize: 15,
                      border: '1.5px solid', borderColor: editMode ? '#a5f3fc' : '#f1f5f9',
                      background: editMode ? '#fff' : '#f8fafc',
                      color: editMode ? '#0f172a' : '#64748b',
                      cursor: !editMode ? 'not-allowed' : 'default', appearance: 'none'
                    }}>
                    <option value="">Select gender</option>
                    <option value="Male">Male</option>
                    <option value="Female">Female</option>
                    <option value="Other">Other</option>
                    <option value="PreferNotToSay">Prefer not to say</option>
                  </select>
                </div>
              </div>

              {editMode && (
                <div style={{ padding: '0 32px 32px', display: 'flex', gap: 12 }}>
                  <button className="action-btn" onClick={handleSaveProfile} disabled={loading}
                    style={{ flex: 1, padding: '13px', borderRadius: 10, fontWeight: 600, fontSize: 15, border: 'none', background: 'linear-gradient(135deg, #059669, #10b981)', color: '#fff', boxShadow: '0 4px 14px rgba(5,150,105,0.25)' }}>
                    {loading ? 'Saving...' : '✓ Save Changes'}
                  </button>
                  <button className="action-btn" onClick={() => { setEditMode(false); fetchProfile(); }}
                    style={{ flex: 1, padding: '13px', borderRadius: 10, fontWeight: 600, fontSize: 15, border: '1.5px solid #e2e8f0', background: '#fff', color: '#64748b' }}>
                    Cancel
                  </button>
                </div>
              )}
            </div>
          </div>
        )}

        {/* ── TAB: ADDRESSES ── */}
        {activeTab === 'addresses' && (
          <div className="fade-in">
            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 24 }}>
              <div>
                <h2 style={{ fontSize: 22, fontWeight: 700, color: '#0f172a' }}>Saved Addresses</h2>
                <p style={{ fontSize: 14, color: '#94a3b8', marginTop: 2 }}>{profileData.addresses?.length || 0} address{profileData.addresses?.length !== 1 ? 'es' : ''} saved</p>
              </div>
              <button className="action-btn" onClick={handleAddAddress}
                style={{ padding: '12px 24px', borderRadius: 12, fontWeight: 600, fontSize: 14, border: 'none', background: 'linear-gradient(135deg, #0891b2, #06b6d4)', color: '#fff', boxShadow: '0 4px 14px rgba(6,182,212,0.3)', display: 'flex', alignItems: 'center', gap: 8 }}>
                <span style={{ fontSize: 18 }}>+</span> Add Address
              </button>
            </div>

            {!profileData.addresses || profileData.addresses.length === 0 ? (
              <div style={{ textAlign: 'center', padding: '80px 32px', background: '#fff', borderRadius: 20, border: '2px dashed #e2e8f0' }}>
                <div style={{ fontSize: 56, marginBottom: 16 }}>📍</div>
                <h3 style={{ fontSize: 18, fontWeight: 600, color: '#334155', marginBottom: 8 }}>No addresses yet</h3>
                <p style={{ color: '#94a3b8', marginBottom: 24 }}>Add your first delivery address</p>
                <button className="action-btn" onClick={handleAddAddress}
                  style={{ padding: '12px 28px', borderRadius: 12, fontWeight: 600, fontSize: 14, border: 'none', background: 'linear-gradient(135deg, #0891b2, #06b6d4)', color: '#fff' }}>
                  + Add Address
                </button>
              </div>
            ) : (
              <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(320px, 1fr))', gap: 16 }}>
                {profileData.addresses.map((addr, idx) => (
                  <div key={addr.id} className="addr-card" style={{ background: '#fff', borderRadius: 16, border: `2px solid ${addr.IsDefault ? '#a5f3fc' : '#f1f5f9'}`, padding: 24, position: 'relative', boxShadow: addr.IsDefault ? '0 4px 20px rgba(6,182,212,0.1)' : '0 2px 8px rgba(0,0,0,0.04)' }}>
                    {addr.IsDefault && (
                      <div style={{ position: 'absolute', top: 16, right: 52, background: '#ecfeff', border: '1px solid #a5f3fc', color: '#0891b2', fontSize: 11, fontWeight: 700, padding: '3px 10px', borderRadius: 999, letterSpacing: 0.5 }}>
                        ⭐ DEFAULT
                      </div>
                    )}
                    <button className="action-btn" onClick={() => handleDeleteAddress(addr)}
                      style={{ position: 'absolute', top: 14, right: 14, width: 32, height: 32, borderRadius: 8, border: '1px solid #fee2e2', background: '#fff', color: '#ef4444', display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: 15 }}>
                      ×
                    </button>
                    <div style={{ fontSize: 13, fontWeight: 700, color: '#0891b2', textTransform: 'uppercase', letterSpacing: 0.5, marginBottom: 10 }}>
                      {addr.label || `Address ${idx + 1}`}
                    </div>
                    <div style={{ fontSize: 15, color: '#334155', lineHeight: 1.6 }}>
                      {[addr.AddressLine1, addr.AddressLine2, addr.City, addr.State, addr.PostalCode, addr.Country].filter(Boolean).join(', ')}
                    </div>
                  </div>
                ))}
              </div>
            )}
          </div>
        )}

        {/* ── TAB: ORDERS ── */}
        {activeTab === 'orders' && (
          <div className="fade-in">
            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 24 }}>
              <div>
                <h2 style={{ fontSize: 22, fontWeight: 700, color: '#0f172a' }}>Order History</h2>
                <p style={{ fontSize: 14, color: '#94a3b8', marginTop: 2 }}>{orders.length} order{orders.length !== 1 ? 's' : ''} total</p>
              </div>
              <button className="action-btn" onClick={() => setCurrentPage('products')}
                style={{ padding: '10px 20px', borderRadius: 10, fontWeight: 600, fontSize: 14, border: 'none', background: 'linear-gradient(135deg, #0891b2, #06b6d4)', color: '#fff' }}>
                + New Order
              </button>
