                  const st = statusConfig[order.status] || statusConfig.Processing;
                  return (
                    <div key={order.id || idx} className="order-row"
                      style={{ display: 'grid', gridTemplateColumns: '1fr 140px 120px 120px', padding: '18px 24px', borderBottom: idx < orders.length - 1 ? '1px solid #f1f5f9' : 'none', alignItems: 'center', cursor: 'pointer' }}
                      onClick={() => setCurrentPage('orders')}>
                      <div>
                        <div style={{ fontWeight: 600, color: '#0f172a', fontSize: 15 }}>Order #{order.orderNumber || order.id}</div>
                        <div style={{ fontSize: 12, color: '#94a3b8', marginTop: 2 }}>{order.items?.length || 0} item{order.items?.length !== 1 ? 's' : ''}</div>
                      </div>
                      <div style={{ fontSize: 14, color: '#64748b' }}>
                        {order.orderDate || order.createdAt
                          ? new Date(order.orderDate || order.createdAt).toLocaleDateString('en-IN', { day: 'numeric', month: 'short', year: 'numeric' })
                          : '—'}
                      </div>
                      <div style={{ fontWeight: 700, color: '#0f172a', fontSize: 15 }}>
                        ₹{(order.totalAmount || 0).toLocaleString('en-IN')}
                      </div>
                      <div>
                        <span style={{ display: 'inline-flex', alignItems: 'center', gap: 6, background: st.bg, color: st.color, padding: '4px 12px', borderRadius: 999, fontSize: 12, fontWeight: 600 }}>
                          <span style={{ width: 6, height: 6, borderRadius: '50%', background: st.dot, flexShrink: 0 }} />
                          {order.status || 'Processing'}
                        </span>
                      </div>
                    </div>
                  );
                })}
              </div>
            )}
          </div>
        )}
      </div>
    </div>
  );
};

export default ProfilePage;
